// Parsear y validar la respuesta del usuario para el paso actual de onboarding
// SP-04 define qué espera cada paso
// __t0_llm capturado aquí para latencia del span LangFuse (R4)
const paso = $input.first().json.onboarding_paso_actual;
const respuesta = $input.first().json.content?.body ?? '';
const datosAcumulados = $input.first().json.datos_onboarding_parciales ?? {};

// Validación básica por paso
// Paso 1: nombre de la finca
// Paso 2: cultivo principal (cacao | banano)
// Paso 3: país (ecuador | guatemala)
// Paso 4: número de lotes
// Paso 5: consentimiento (sí | no)

const PASOS_VALIDOS = {
  1: { campo: 'finca_nombre', validar: (r) => r.trim().length >= 2 },
  2: { campo: 'cultivo_principal', validar: (r) => ['cacao', 'banano', 'cacao y banano', 'banano y cacao'].some(c => r.toLowerCase().includes(c)) },
  3: { campo: 'pais', validar: (r) => ['ecuador', 'guatemala'].some(p => r.toLowerCase().includes(p)) },
  4: { campo: 'num_lotes', validar: (r) => !isNaN(parseInt(r.match(/\d+/)?.[0])) },
  5: { campo: 'consentimiento', validar: (r) => ['sí', 'si', 'no'].some(c => r.toLowerCase().trim() === c) }
};

const pasoConfig = PASOS_VALIDOS[paso];
if (!pasoConfig) throw new Error(`PASO_INVALIDO: ${paso}`);

const esValido = pasoConfig.validar(respuesta);

if (esValido) {
  let valorParseado = respuesta.trim();
  if (paso === 4) valorParseado = parseInt(respuesta.match(/\d+/)[0]);
  if (paso === 5) valorParseado = respuesta.toLowerCase().trim() === 'sí' || respuesta.toLowerCase().trim() === 'si';

  const nuevosDatos = { ...datosAcumulados, [pasoConfig.campo]: valorParseado };
  const siguientePaso = paso + 1;
  const onboardingCompleto = paso >= 5;

  return [{
    json: {
      ...$input.first().json,
      paso_actual: paso,
      siguiente_paso: siguientePaso,
      onboarding_completo: onboardingCompleto,
      datos_actualizados: nuevosDatos,
      respuesta_valida: true,
      campo_guardado: pasoConfig.campo,
      valor_guardado: valorParseado
    }
  }];
} else {
  return [{
    json: {
      ...$input.first().json,
      paso_actual: paso,
      respuesta_valida: false,
      datos_actualizados: datosAcumulados
    }
  }];
}
